mapper.select:
SELECT

FROM diagnosis_recommendation
WHERE tenant_id = #{tenantId}
  AND id = #{id}

SELECT

FROM diagnosis_recommendation
WHERE tenant_id = #{tenantId}
  AND session_id = #{sessionId}
ORDER BY priority ASC, id DESC

mapper.update:
UPDATE diagnosis_recommendation
SET session_id = #{sessionId},
    rec_type = #{recType},
    content = #{content},
    priority = #{priority},
    reason = #{reason}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
DELETE
FROM diagnosis_recommendation
WHERE tenant_id = #{tenantId}
  AND id = #{id}
